const now = () => Date.now()/1000;
const ri = (a,b) => Math.floor(Math.random()*(b-a+1))+a;
const pick = arr => arr[Math.floor(Math.random()*arr.length)];
function sample(arr,n){const c=arr.slice();const o=[];for(let i=0;i<n&&c.length;i++){o.push(c.splice(Math.floor(Math.random()*c.length),1)[0]);}return o;}
function shuffle(a){for(let i=a.length-1;i>0;i--){const j=Math.floor(Math.random()*(i+1));[a[i],a[j]]=[a[j],a[i]];}return a;}

function freshRoom(){
  return {version:1,matchId:0,phase:'lobby',players:[null,null],scores:[0,0],
    night:{wins:[0,0],matches:0},first:0,rounds:[],roundIndex:0,roundType:null,picker:0,
    letters:[],vowels:0,cons:0,numbers:null,target:0,scram:'',_answer:'',
    subs:[null,null],done:[false,false],buzz:null,result:null,boardAt:0};
}
let ROOM = freshRoom();
const bump = () => { ROOM.version++; };

function setupRound(idx){
  const r=ROOM;
  r.roundType=r.rounds[idx]; r.picker=(idx+r.first)%2;
  r.letters=[];r.vowels=0;r.cons=0;r.numbers=null;r.target=0;r.scram='';r._answer='';
  r.subs=[null,null];r.done=[false,false];r.buzz=null;r.result=null;r.boardAt=0;r.phase='round';
  if(r.roundType==='conundrum'){
    const w=pick(CONUNDRUM_WORDS);let s=w.split('');
    while(s.join('')===w) shuffle(s);
    r._answer=w;r.scram=s.join('');r.boardAt=now();
  }
}
function drawLetter(kind){
  const r=ROOM; if(r.letters.length>=9) return;
  if(kind==='v'){r.letters.push(pick(VOWEL_BAG));r.vowels++;}
  else{r.letters.push(pick(CONS_BAG));r.cons++;}
  if(r.letters.length===9) r.boardAt=now();
}
function autoFill(){
  const r=ROOM;
  while(r.letters.length<9){
    const left=9-r.letters.length;
    if(r.vowels<3&&left<=(3-r.vowels)) drawLetter('v');
    else if(r.cons<4&&left<=(4-r.cons)) drawLetter('c');
    else if(Math.random()<0.42&&r.vowels<5) drawLetter('v');
    else if(r.cons<6) drawLetter('c');
    else drawLetter('v');
  }
}
function dealNumbers(numLarge){
  const r=ROOM; numLarge=Math.max(0,Math.min(4,parseInt(numLarge,10)||0));
  const large=sample([25,50,75,100],numLarge);
  let bag=[];for(let n=1;n<=10;n++){bag.push(n,n);}shuffle(bag);
  const small=bag.slice(0,6-numLarge);
  const nums=shuffle(large.concat(small));
  r.numbers=nums;r.target=ri(101,999);r.boardAt=now();
}
const lenScore = w => !w?0:(w.length===9?18:w.length);
const numScore = d => d===0?10:d<=5?7:d<=10?5:0;

function finalizeRound(){
  const r=ROOM,rt=r.roundType;
  if(rt==='letters'){
    const w0=(r.subs[0]||{}).word||'',w1=(r.subs[1]||{}).word||'';
    const p0=lenScore(w0),p1=lenScore(w1);let a0=0,a1=0,winner=null;
    if(w0.length>w1.length){a0=p0;winner=0;}
    else if(w1.length>w0.length){a1=p1;winner=1;}
    else{a0=p0;a1=p1;}
    r.scores[0]+=a0;r.scores[1]+=a1;
    r.result={subs:[{word:w0,pts:a0},{word:w1,pts:a1}],winner};
  } else if(rt==='numbers'){
    const v0=(r.subs[0]||{}).value,v1=(r.subs[1]||{}).value;
    const d0=Number.isInteger(v0)?Math.abs(v0-r.target):1e9;
    const d1=Number.isInteger(v1)?Math.abs(v1-r.target):1e9;
    let a0=0,a1=0,winner=null;
    if(d0<d1){a0=numScore(d0);winner=0;}
    else if(d1<d0){a1=numScore(d1);winner=1;}
    else if(d0<1e9){a0=numScore(d0);a1=numScore(d0);}
    r.scores[0]+=a0;r.scores[1]+=a1;
    r.result={subs:[{value:v0??null,pts:a0},{value:v1??null,pts:a1}],winner};
  }
  r.phase='reveal';
}
function finalizeMatch(){
  const r=ROOM,[s0,s1]=r.scores;
  if(s0>s1)r.night.wins[0]++;else if(s1>s0)r.night.wins[1]++;
  r.phase='matchover';
}
function checkTimeouts(){
  const r=ROOM; if(r.phase!=='round'||r.boardAt<=0)return;
  const t=now()-r.boardAt;
  if(r.roundType==='conundrum'){
    if(t>33&&!r.buzz){r.result={conWord:r._answer,winner:null};r.phase='reveal';bump();}
  } else if(t>40&&!(r.done[0]&&r.done[1])){finalizeRound();bump();}
}
function pub(){
  const r=ROOM;
  const pv=p=>p?{name:p.name,connected:(now()-p.lastSeen<3)}:null;
  return {version:r.version,matchId:r.matchId,phase:r.phase,
    players:[pv(r.players[0]),pv(r.players[1])],scores:r.scores,night:r.night,
    rounds:r.rounds,roundIndex:r.roundIndex,roundType:r.roundType,picker:r.picker,
    letters:r.letters,vowels:r.vowels,cons:r.cons,numbers:r.numbers,target:r.target,scram:r.scram,
    submitted:[r.done[0],r.done[1]],buzz:r.buzz?r.buzz.seat:null,result:r.result};
}
function findSeat(pid){for(let i=0;i<2;i++){if(ROOM.players[i]&&ROOM.players[i].id===pid)return i;}return -1;}
function handleJoin(pid,name){
  let seat=findSeat(pid);
  if(seat>=0){ROOM.players[seat].name=name||ROOM.players[seat].name;ROOM.players[seat].lastSeen=now();return seat;}
  for(let i=0;i<2;i++){if(!ROOM.players[i]){ROOM.players[i]={id:pid,name:name||('Player '+(i+1)),lastSeen:now()};bump();return i;}}
  return -1;
}
function handleAct(d){
  const pid=d.id,typ=d.type,r=ROOM;const seat=findSeat(pid);const extra={};
  if(seat>=0)r.players[seat].lastSeen=now();
  if(typ==='leave'){if(seat>=0){r.players[seat]=null;bump();}return extra;}
  if(typ==='startMatch'&&seat===0&&r.phase==='lobby'&&r.players[0]&&r.players[1]){
    r.rounds=ROUND_SETS[d.len]||ROUND_SETS.standard;r.matchId++;r.night.matches++;
    r.scores=[0,0];r.first=0;r.roundIndex=0;setupRound(0);bump();return extra;
  }
  if(typ==='pickLetter'&&r.phase==='round'&&r.roundType==='letters'&&seat===r.picker){
    if(d.kind==='auto'){autoFill();bump();}
    else if(r.letters.length<9){
      const left=9-r.letters.length;
      if(d.kind==='v'&&!(r.vowels>=5||left<=(4-r.cons))){drawLetter('v');bump();}
      else if(d.kind==='c'&&!(r.cons>=6||left<=(3-r.vowels))){drawLetter('c');bump();}
    }
    return extra;
  }
  if(typ==='dealNumbers'&&r.phase==='round'&&r.roundType==='numbers'&&seat===r.picker&&r.numbers===null){
    dealNumbers(d.large||0);bump();return extra;
  }
  if(typ==='submit'&&r.phase==='round'&&(seat===0||seat===1)&&(r.roundType==='letters'||r.roundType==='numbers')){
    if(r.roundType==='letters'){const w=(d.word||'').toLowerCase();r.subs[seat]={word:/^[a-z]+$/.test(w)?w:''};}
    else{const v=d.value;r.subs[seat]={value:(typeof v==='number')?Math.round(v):null};}
    r.done[seat]=true;
    if(r.done[0]&&r.done[1])finalizeRound();
    bump();return extra;
  }
  if(typ==='buzz'&&r.phase==='round'&&r.roundType==='conundrum'&&(seat===0||seat===1)){
    if(r.buzz===null&&(d.word||'').toLowerCase()===r._answer){
      r.buzz={seat};r.scores[seat]+=10;r.result={conWord:r._answer,winner:seat};r.phase='reveal';bump();
      extra.buzzAccepted=true;
    } else extra.buzzAccepted=false;
    return extra;
  }
  if(typ==='next'&&r.phase==='reveal'){
    r.roundIndex++;
    if(r.roundIndex>=r.rounds.length)finalizeMatch();else setupRound(r.roundIndex);
    bump();return extra;
  }
  if(typ==='rematch'&&seat===0&&r.phase==='matchover'){
    r.matchId++;r.night.matches++;r.scores=[0,0];r.first=1-r.first;r.roundIndex=0;setupRound(0);bump();return extra;
  }
  return extra;
}

function sendJSON(res,code,obj){
  const body=Buffer.from(JSON.stringify(obj));
  res.writeHead(code,{'Content-Type':'application/json','Content-Length':body.length,
    'Access-Control-Allow-Origin':'*','Access-Control-Allow-Headers':'Content-Type','Cache-Control':'no-store'});
  res.end(body);
}
const server=http.createServer((req,res)=>{
  const u=new URL(req.url,'http://x');
  if(req.method==='OPTIONS'){res.writeHead(204,{'Access-Control-Allow-Origin':'*','Access-Control-Allow-Headers':'Content-Type'});return res.end();}
  if(req.method==='GET'){
    if(u.pathname==='/'||u.pathname==='/index.html'||u.pathname==='/countdown-lan.html'){
      fs.readFile(HTML_PATH,(e,data)=>{
        if(e){res.writeHead(500,{'Content-Type':'text/plain'});return res.end('countdown-lan.html not found next to server.js');}
        res.writeHead(200,{'Content-Type':'text/html; charset=utf-8','Cache-Control':'no-store','Content-Length':data.length});res.end(data);
      });return;
    }
    if(u.pathname==='/api/state'){
      checkTimeouts();const pid=u.searchParams.get('id')||'';const s=findSeat(pid);if(s>=0)ROOM.players[s].lastSeen=now();
      return sendJSON(res,200,{version:ROOM.version,room:pub()});
    }
    return sendJSON(res,404,{error:'not found'});
  }
  if(req.method==='POST'){
    let body='';req.on('data',c=>{body+=c;if(body.length>1e6)req.destroy();});
    req.on('end',()=>{
      let d={};try{d=JSON.parse(body||'{}');}catch(e){d={};}
      if(u.pathname==='/api/join'){checkTimeouts();const seat=handleJoin(d.id||'',((d.name||'').trim()).slice(0,14));return sendJSON(res,200,{seat,version:ROOM.version,room:pub()});}
      if(u.pathname==='/api/act'){checkTimeouts();const extra=handleAct(d);return sendJSON(res,200,Object.assign({ok:true,version:ROOM.version,room:pub()},extra));}
      return sendJSON(res,404,{error:'not found'});
    });return;
  }
  sendJSON(res,404,{error:'not found'});
});

function lanIps(){
  const out=[];const ifs=os.networkInterfaces();
  for(const name in ifs){for(const i of ifs[name]){if(i.family==='IPv4'&&!i.internal)out.push(i.address);}}
  return out;
}
let port=8000;
if(process.argv[2]){const p=parseInt(process.argv[2],10);if(!isNaN(p))port=p;}
server.listen(port,'0.0.0.0',()=>{
  console.log('\n  The Countdown Game  —  LAN host is running');
  console.log('  '+'-'.repeat(44));
  const ips=lanIps();
  console.log('  On THIS computer, open:   http://localhost:'+port);
  if(ips.length){console.log('  On the OTHER computer(s), open one of:');ips.forEach(ip=>console.log('       http://'+ip+':'+port));}
  console.log('  '+'-'.repeat(44));
  console.log('  Both players: open the address, then choose "Play over LAN".');
  console.log('  Press Ctrl+C to stop.\n');
});
